from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English paragraph. Handles mission/crewMembers aggregation to
    produce compact sentences.
    """
    if not triples:
        return ""

    # ---------- Helper utilities ----------
    def fmt_date(d: str) -> str:
        try:
            from datetime import datetime
            dt = datetime.strptime(d, "%Y-%m-%d")
            # Use platform‑independent day format
            return dt.strftime("%B %-d, %Y") if hasattr(dt, "strftime") else dt.strftime("%B %d, %Y")
        except Exception:
            return d

    def join_names(names: list[str]) -> str:
        """Join a list of names with commas and 'and'."""
        if not names:
            return ""
        if len(names) == 1:
            return names[0]
        if len(names) == 2:
            return f"{names[0]} and {names[1]}"
        return f"{', '.join(names[:-1])}, and {names[-1]}"

    # ---------- Phrase builder ----------
    def phrase(subj: str, pred: str, obj: str) -> str:
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            low = obj.lower()
            if low in ("united states", "usa", "united states of america"):
                return "is an American"
            return f"is from {obj}"
        if p == "occupation":
            return f"served as a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is now retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                parts = []
                if hrs:
                    parts.append(f"{hrs} hour{'s' if hrs != 1 else ''}")
                if rem:
                    parts.append(f"{rem} minute{'s' if rem != 1 else ''}")
                return "spent " + " and ".join(parts) + " in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"was operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{obj} was the backup pilot of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # generic fallback
        return f"is {obj}"

    # ---------- Aggregate mission/crew data ----------
    from collections import defaultdict

    # Data structure per mission
    mission_data: dict[str, dict] = defaultdict(lambda: {
        "crew": [],          # list of astronaut names
        "commander": None,
        "backup": None,
        "operator": None
    })
    other_triples: list[Triple] = []

    for t in triples:
        p = t.predicate.lower().replace(" ", "")
        if p == "mission":
            # astronaut -> mission
            data = mission_data[t.object]
            if t.subject not in data["crew"]:
                data["crew"].append(t.subject)
        elif p == "crewmembers":
            # mission -> astronaut
            data = mission_data[t.subject]
            if t.object not in data["crew"]:
                data["crew"].append(t.object)
        elif p == "commander":
            mission_data[t.subject]["commander"] = t.object
        elif p == "backuppilot":
            mission_data[t.subject]["backup"] = t.object
        elif p == "operator":
            mission_data[t.subject]["operator"] = t.object
        else:
            other_triples.append(t)

    sentences: list[str] = []

    # Build a compact sentence for each mission
    for mission, data in mission_data.items():
        crew_names = data["crew"]
        crew_str = join_names(crew_names)
        parts: list[str] = []

        if crew_str:
            if len(crew_names) == 1:
                parts.append(f"{crew_str} was a crew member of {mission}")
            else:
                parts.append(f"{crew_str} were crew members of {mission}")

        if data["operator"]:
            parts.append(f"operated by {data['operator']}")

        role_phrases: list[str] = []
        if data["commander"]:
            role_phrases.append(f"{data['commander']} as commander")
        if data["backup"]:
            role_phrases.append(f"{data['backup']} as backup pilot")
        if role_phrases:
            parts.append("with " + " and ".join(role_phrases))

        sentence = ", ".join(parts) + "."
        sentences.append(sentence)

    # Process remaining triples (those not mission/crewMembers/commander/backup/operator)
    # Group by subject
    groups = defaultdict(list)
    for t in other_triples:
        groups[t.subject].append(t)

    for subj, items in groups.items():
        descriptors = [phrase(subj, t.predicate, t.object) for t in items]
        if not descriptors:
            continue
        if len(descriptors) == 1:
            sentences.append(f"{subj} {descriptors[0]}.")
        else:
            body = ", ".join(descriptors[:-1])
            sentences.append(f"{subj} {body}, and {descriptors[-1]}.")
    return " ".join(sentences)

# EVOLVE-BLOCK-END

